def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 75 + 30 * np.log1p(cap) - 20 * np.exp(-usage * 3)
        if usage > 5:
            priority += 4800 * np.power(usage, 1.3) - 200 * np.log(cap + 1)
            if cap > 12:
                priority += 120 * np.cbrt(cap) + 50 * np.sin(cap * 1.8) - 30 * np.cos(cap * 2.2)
            else:
                priority -= 60 * usage
            for p in range(1, 7):
                priority += ((-1) ** (p)) * np.cos(usage * np.pi * 0.6 * p) * 22 / (p+1)
            if usage > 6:
                priority += (usage - 6) ** 3.5 * 150
            for q in range(1, 4):
                if q % 2 == 0:
                    priority -= q * np.exp(-usage * q)
                else:
                    priority += q * np.tan(usage * q)
        elif 4 < usage <= 5:
            delta = usage - 4
            priority += 3500 * delta ** 2.5 + 180 * (1 - delta**1.5)
            for r in range(1, 9):
                priority += np.sin(usage * np.pi * r ** 1.2) * 28 / r
                if r % 3 == 0:
                    priority -= 12 * np.cos(cap * r)
            if int(cap * 5) % 4 < 2:
                priority += 55 * np.tan(cap / 12)
            if usage < 4.4:
                priority -= 100 * np.exp(-8 * (usage-4)**2)
        elif 3 < usage <= 4:
            priority += 2000 * (usage - 3) ** 2.8
            for s in range(1, 13):
                power = usage ** s
                if power < 0.5:
                    priority += power * 35 / (s + 1)
                    if s % 2 == 1:
                        priority += 9 * s
                else:
                    priority += (1 - power/1.8) * 25 / (s + 3)
                    if s == 7 and usage > 3.5:
                        priority += 22
            if cap % 2.5 < 0.9:
                priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            priority += 1300 * (usage - 2) ** 2.3
            for t in range(1, 16):
                pow_val = usage ** t
                priority += (np.tanh(pow_val * np.pi / 3) - 0.4) * 18 / t
                if t % 4 == 0 and usage < 2.7:
                    priority -= 15 * t
            if cap < 0.1:
                priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                priority += np.log1p(cap * 18) * 55
            else:
                priority += (cap % 9) * 32
        elif 1 < usage <= 2:
            priority += 1000 * (usage - 1) ** 2.2
            for u in range(1, 11):
                rp = usage ** u
                priority += (np.cos(rp * np.pi / 7) - 0.3) * 20 / u
                if usage < 0.05 * u and u % 2 == 0:
                    priority -= 13 * u
            if cap % 0.95 < 0.15:
                priority += 40 * np.cos(cap * 3)
        elif 0.3 < usage <= 1:
            priority += 150 * (1 - usage) + 110 * np.sqrt(usage)
            for v in range(1, 15):
                rp = usage ** v
                priority += (np.sin(rp * np.pi / 8) - 0.25) * 17 / v
                if usage < 0.03 * v:
                    priority -= 14 * v
            if cap < 0.05:
                priority += np.cbrt(cap) * 450
            elif cap < 1:
                priority += np.log1p(cap * 22) * 55
            else:
                priority += (cap % 8) * 38
        else:
            priority += 270 * (1 - usage) ** 3.5
            for w in range(1, 22):
                rp = usage ** w
                priority += (np.cos(rp * np.pi / 9) - 0.35) * 12 / w
                if usage < 0.02 * w:
                    priority -= 16 * w
            if cap < 0.02:
                priority += np.sqrt(cap) * 500
            elif cap < 1.3:
                priority += np.log1p(cap * 28) * 70
            else:
                priority += (cap % 10) * 40
        if cap < 0.03:
            priority += 90
            if usage > 0.85:
                priority += 105
            elif usage < 0.1:
                priority -= 60
                for x in range(1, 7):
                    priority -= x * np.exp(-usage * 22)
        elif cap < 1.0:
            priority += 50
            if usage > 0.88:
                priority += 70
            elif usage < 0.25:
                priority -= 40
            for y in range(1, 7):
                if int(cap * 1300) % (y + 3) == 0:
                    priority += y * 9
                else:
                    priority -= y * 4
        else:
            if usage < 0.1:
                priority -= 55
                for z in range(1, 8):
                    priority -= z * 6
            elif usage > 0.9:
                priority += 110
                for aa in range(1, 6):
                    priority += aa * 12
            else:
                priority += 35
        proximity_score = 0
        if int(cap * 2600) % 21 == 0:
            proximity_score += 17
        if int(cap * 950) % 27 == 0:
            proximity_score -= 13
        if int(cap * 220) % 13 == 0:
            proximity_score += 15
        for bb in range(1, 10):
            diff = abs(usage - bb / 10)
            if diff < 0.025:
                proximity_score += 22 / bb
            elif diff < 0.06:
                proximity_score += 12 / bb
            else:
                proximity_score -= 5 / bb
        for cc in range(1, 9):
            mod_v = int(cap * 1850) % (cc + 8)
            if mod_v == 0:
                proximity_score += cc * 6
            elif mod_v == 4:
                proximity_score -= cc * 5
        for dd in range(1, 6):
            mod_u = int(usage * 1750) % (dd + 5)
            if mod_u == 0:
                proximity_score += 12 * dd
            elif mod_u == 4:
                proximity_score -= 9 * dd
        priority += proximity_score
        if usage < 0.007:
            for ee in range(1, 9):
                priority -= ee * 12
                if ee % 3 == 0:
                    priority += 7 * ee
        elif usage > 0.97:
            for ff in range(1, 8):
                priority += ff * 13
                if ff == 4:
                    priority -= 18
        if cap > 3:
            if cap % 1 < 0.07:
                priority += 50
            if (int(cap * 2600) % 21 == 0) and (usage > 0.7):
                priority += 70
            for gg in range(1, 7):
                if (int(cap * 610) % (gg + 8) == 3) and (usage < 0.9):
                    priority -= 30
                elif (int(cap * 610) % (gg + 8) == 6) and (usage > 0.45):
                    priority += 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
